-- {"operators": "OUTER_JOIN,AGGREGATE,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": false, "tables": "ITEM,STOCK,ORDER_LINE", "ducklake": true}
WITH demand AS (SELECT OL_I_ID, OL_SUPPLY_W_ID, SUM(OL_QUANTITY) AS qty_ordered FROM dl.ORDER_LINE GROUP BY OL_I_ID, OL_SUPPLY_W_ID) SELECT s.S_W_ID, i.I_ID, (s.S_QUANTITY - COALESCE(d.qty_ordered, 0)) AS remaining, (i.I_PRICE * COALESCE(d.qty_ordered, 0)) AS revenue FROM dl.STOCK s JOIN dl.ITEM i ON s.S_I_ID = i.I_ID LEFT JOIN demand d ON s.S_W_ID = d.OL_SUPPLY_W_ID AND s.S_I_ID = d.OL_I_ID;
